select a.adviceId, a.adviceReference, a.attachmentIds, d.documentId 
from [odw_curated_db].[dbo].[nsip_s51_advice] a
left join [odw_curated_db].[dbo].[document_meta_data] d on a.attachmentIds = d.documentId
where caseReference where a.attachmentIds is not null and d.documentId is not null;

select * from [odw_curated_db].[dbo].[document_meta_data] t1 
inner join [odw_harmonised_db].[dbo].[document_tree_dim] t2 on t1.documentID = t2.DataID
right join [odw_curated_db].[dbo].[nsip_s51_advice] t3 on t3.CaseReference = t1.caseRef
where t2.isActive = 'Y' and t3.attachmentIds is not null and caseReference = 'EN010007';

select count(*) from [odw_curated_db].[dbo].[nsip_s51_advice];


select count(*) from [odw_curated_db].[dbo].[document_meta_data];
